function normalizeShift(v){return legacyShiftMap[v]||v} function normalizeTeam(v){return legacyTeamMap[v]||v} function normalizeEntry(e){return {...e,shift:normalizeShift(e.shift),team:normalizeTeam(e.team),project:normalizeMasterValue(e.project),product:normalizeMasterValue(e.product),machine:normalizeMasterValue(e.machine),lossReason:normalizeMasterValue(e.lossReason)}} function save(){localStorage.setItem(STORAGE_KEY,JSON.stringify(entries));localStorage.setItem(MASTER_KEY,JSON.stringify(master))} function t(k){return tx[lang]?.[k]||tx.en[k]||k} function label(v){if(!v)return '';const item=typeof v==='object'?v:findMasterItem(v);if(item)return itemLabel(item);return systemLabels[lang]?.[v]||systemLabels.en[v]||masterLabels[lang]?.[v]||masterLabels.en?.[v]||(/^[a-z0-9]+(_[a-z0-9]+)+$/.test(String(v))?'':String(v))} function n(v){return Number(v||0)} function fmt(v){return n(v).toLocaleString(locales[lang])} function pct(v){return `${n(v).toLocaleString(locales[lang],{maximumFractionDigits:0})}%`} function calc(e){const good=n(e.produced)-n(e.scrap), dev=good-n(e.target), lost=Math.max(n(e.target)-good,0), ach=n(e.target)?good/n(e.target)*100:0;return{good,dev,lost,ach}} function status(ach){return ach>=100?'green':ach>=90?'yellow':'red'}
