function clearValidationMessageTimer(){if(validationMessageTimer){clearTimeout(validationMessageTimer);validationMessageTimer=null}} function setValidationMessage(message,type){clearValidationMessageTimer();validationMessageToken++;const el=$('validationMessage');el.textContent=message;el.classList.remove('success','error');if(type)el.classList.add(type);return validationMessageToken} function flash(key){const token=setValidationMessage(t(key),'success');validationMessageTimer=setTimeout(()=>{if(token===validationMessageToken){setValidationMessage('',null)}},VALIDATION_SUCCESS_TIMEOUT)} function translateStatic(){document.documentElement.lang=lang;document.documentElement.classList.remove('pre-i18n');document.title=t('pageTitle');document.querySelectorAll('[data-i18n]').forEach(el=>el.textContent=t(el.dataset.i18n));document.querySelectorAll('[data-i18n-aria]').forEach(el=>el.setAttribute('aria-label',t(el.dataset.i18nAria)));document.querySelectorAll('[data-i18n-title]').forEach(el=>el.setAttribute('title',t(el.dataset.i18nTitle)));document.querySelectorAll('[data-i18n-placeholder]').forEach(el=>el.setAttribute('placeholder',t(el.dataset.i18nPlaceholder)));}
