function drawLegend(ctx,items,x,y,colors,maxW=Infinity){ctx.font='600 12px Inter, Segoe UI, Arial, sans-serif';ctx.textBaseline='middle';let cx=x,cy=y,lineH=22;items.forEach(it=>{const label=it.shortLabel&&textWidth(ctx,it.label,'600 12px Inter, Segoe UI, Arial, sans-serif')>maxW*.58?it.shortLabel:it.label,markerW=it.type==='traffic'?38:it.type==='line'?24:18,labelX=markerW+(it.type==='line'?8:8),itemW=labelX+textWidth(ctx,label,'600 12px Inter, Segoe UI, Arial, sans-serif')+30;if(cx>x&&cx+itemW>x+maxW){cx=x;cy+=lineH}ctx.strokeStyle=it.color;ctx.fillStyle=it.color;ctx.lineWidth=3;if(it.type==='line'){ctx.beginPath();ctx.setLineDash(it.dash||[]);ctx.moveTo(cx,cy);ctx.lineTo(cx+24,cy);ctx.stroke();ctx.setLineDash([])}else if(it.type==='traffic'){[colors.green,colors.yellow,colors.red].forEach((color,i)=>{const sx=cx+i*13;ctx.fillStyle=color;ctx.beginPath();ctx.roundRect(sx,cy-6,10,12,2);ctx.fill()})}else ctx.fillRect(cx,cy-5,18,10);ctx.fillStyle=colors.text;ctx.fillText(label,cx+labelX,cy,Math.max(80,maxW-(cx-x)-labelX));cx+=itemW})}
