function targetPrefix(){return lang==='de'?'Ziel':'Target'}
function compactTimeLabel(value){const text=String(value||'');const m=text.match(/(\d{1,2}:\d{2})/);return m?m[1]:text.split(/[–-]/)[0].trim()}
function shouldShowTick(index,total,w){if(total<=1)return true;const last=index===total-1;if(index===0||last)return true;const min= w<420?82:w<640?68:48;const every=Math.max(1,Math.ceil(total*min/Math.max(1,w)));return index%every===0}
function drawXAxisLabels(ctx,labels,plot,colors){const total=labels.length,step=plot.w/Math.max(1,total);ctx.textAlign='center';ctx.fillStyle=colors.muted;ctx.font='11px Inter, Segoe UI, Arial, sans-serif';ctx.textBaseline='alphabetic';labels.forEach((label,i)=>{if(!shouldShowTick(i,total,plot.w))return;const x=plot.l+i*step+step/2,y=plot.t+plot.h+16;ctx.save();ctx.translate(x,y);if(step<42)ctx.rotate(-Math.PI/9);ctx.fillText(compactTimeLabel(label),0,0);ctx.restore()})}
function labelBox(ctx,text,x,y,pad=4){const m=ctx.measureText(String(text)),h=(m.actualBoundingBoxAscent||10)+(m.actualBoundingBoxDescent||3);return {x:x-m.width/2-pad,y:y-h/2-pad,w:m.width+pad*2,h:h+pad*2}}
function intersects(a,b,gap=0){return a.x-gap<b.x+b.w&&a.x+a.w+gap>b.x&&a.y-gap<b.y+b.h&&a.y+a.h+gap>b.y}
