function drawHorizontal(id,obj,axisLabel,unit,color){const {ctx,w,h,colors}=setupChart(id),data=Object.entries(obj).filter(([,v])=>v>0).sort((a,b)=>b[1]-a[1]);if(!data.length){drawEmpty(ctx,w,h,colors);return}const labelW=Math.min(w<520?130:180,Math.max(92,...data.map(([k])=>textWidth(ctx,label(k),'12px Inter, Segoe UI, Arial, sans-serif')+12)));ctx.font='600 12px Inter, Segoe UI, Arial, sans-serif';const valueW=Math.max(...data.map(([,v])=>textWidth(ctx,`${fmt(v)} ${unit}`,ctx.font)))+24,plot={l:labelW,t:26,w:w-labelW-valueW-18,h:h-70};const max=niceMax(Math.max(...data.map(([,v])=>v))*1.06),gap=10,bh=Math.max(14,Math.min(30,(plot.h-(data.length-1)*gap)/data.length));ctx.fillStyle=colors.text;ctx.font='600 12px Inter, Segoe UI, Arial, sans-serif';ctx.textAlign='center';ctx.fillText(axisLabel,plot.l+plot.w/2,h-12);ticks(max).forEach(v=>{const x=plot.l+(v/max)*plot.w;ctx.strokeStyle=colors.line;ctx.beginPath();ctx.moveTo(x,plot.t-6);ctx.lineTo(x,plot.t+plot.h);ctx.stroke()});data.forEach(([k,v],i)=>{const y=plot.t+i*(bh+gap),bw=(v/max)*plot.w,text=`${fmt(v)} ${unit}`;ctx.fillStyle=colors.muted;ctx.font='12px Inter, Segoe UI, Arial, sans-serif';ctx.textAlign='right';ctx.textBaseline='middle';ctx.fillText(label(k),plot.l-10,y+bh/2,labelW-18);ctx.fillStyle=color;ctx.fillRect(plot.l,y,bw,bh);ctx.font='600 12px Inter, Segoe UI, Arial, sans-serif';const outsideX=plot.l+bw+10;if(outsideX+textWidth(ctx,text,ctx.font)<=w-10){ctx.fillStyle=colors.text;ctx.textAlign='left';ctx.fillText(text,outsideX,y+bh/2)}else{ctx.fillStyle='#fff';ctx.textAlign='right';ctx.fillText(text,plot.l+bw-8,y+bh/2)}});ctx.strokeStyle=colors.text;ctx.beginPath();ctx.moveTo(plot.l,plot.t-6);ctx.lineTo(plot.l,plot.t+plot.h);ctx.lineTo(plot.l+plot.w,plot.t+plot.h);ctx.stroke()}
function renderMaster(){const area=$('masterDataArea');area.innerHTML='';const core=document.createElement('div');core.className='master-core-grid';['projects','products','machines'].forEach(k=>core.appendChild(masterBox(t(`master_${k}`),master[k],k)));area.appendChild(core);const reasonSection=document.createElement('section');reasonSection.className='master-reasons-section';reasonSection.innerHTML=`<h3 class="master-section-title">${escapeHtml(t('master_reasons'))}</h3><div class="master-reasons-grid"></div>`;const grid=reasonSection.querySelector('.master-reasons-grid');Object.keys(master.reasons).forEach(k=>grid.appendChild(masterBox(label(k),master.reasons[k],`reason:${k}`,true,k)));area.appendChild(reasonSection)}
function languageFields(namePrefix,values){return `<div class="master-editor-grid"><label><span>English</span><input data-lang="en" name="${namePrefix}-en" value="${escapeHtml(values.en||'')}" aria-label="English"></label><label><span>Deutsch</span><input data-lang="de" name="${namePrefix}-de" value="${escapeHtml(values.de||'')}" aria-label="Deutsch"></label><label><span>Italiano</span><input data-lang="it" name="${namePrefix}-it" value="${escapeHtml(values.it||'')}" aria-label="Italiano"></label></div>`}
function readLanguageFields(scope){const values={en:'',de:'',it:''};scope.querySelectorAll('input[data-lang]').forEach(input=>values[input.dataset.lang]=input.value.trim());const fallback=values.en||values.de||values.it;return {en:values.en||fallback,de:values.de||fallback,it:values.it||fallback}}
function masterBox(title,arr,cat,isReason=false,reasonCat=''){const d=document.createElement('div');d.className=isReason?'master-box master-reason-box':'master-box';const expanded=!isReason||openReasonCats.has(reasonCat);d.innerHTML=isReason?`<button class="master-accordion-toggle" type="button" data-action="toggle" aria-expanded="${expanded}"><span><strong>${escapeHtml(title)}</strong><small> · ${escapeHtml(reasonCountLabel(arr.length))}</small></span><svg class="chevron ${expanded?'is-open':''}" viewBox="0 0 20 20" aria-hidden="true" focusable="false"><path d="M5 7l5 5 5-5"/></svg></button><div class="master-panel" ${expanded?'':'hidden'}><div class="master-list"></div><div class="master-add"></div></div>`:`<h3>${escapeHtml(title)}</h3><div class="master-list"></div><div class="master-add"></div>`;const list=d.querySelector('.master-list'),add=d.querySelector('.master-add'),panel=d.querySelector('.master-panel');function redraw(){const isOpen=!isReason||openReasonCats.has(reasonCat);if(isReason){const toggle=d.querySelector('.master-accordion-toggle');toggle.setAttribute('aria-expanded',String(isOpen));d.querySelector('.chevron').classList.toggle('is-open',isOpen);panel.hidden=!isOpen}list.innerHTML=arr.map((v,i)=>{const key=masterKey(cat,i),editing=masterEditKey===key,draft=masterDrafts[key]||draftFrom(v);if(editing)return `<div class="master-entry is-editing" data-key="${escapeHtml(key)}" data-i="${i}"><div class="master-editor">${languageFields(`edit-${key}`,draft)}<div class="master-entry-actions"><button class="primary" data-action="save" data-i="${i}">${t('save')}</button><button class="secondary" data-action="cancel">${t('cancel')}</button></div></div></div>`;return `<div class="master-entry" data-key="${escapeHtml(key)}" data-i="${i}"><span class="master-entry-label">${escapeHtml(itemLabel(v))}</span><div class="master-entry-actions"><button class="master-icon-button edit" data-action="edit" data-i="${i}" title="${escapeHtml(t('edit'))}" aria-label="${escapeHtml(t('edit'))}">${svgIcon('edit')}</button><button class="master-icon-button delete" data-action="delete" data-i="${i}" title="${escapeHtml(t('delete'))}" aria-label="${escapeHtml(t('delete'))}">${svgIcon('delete')}</button></div></div>`}).join('');add.innerHTML=masterAddKey===cat?`<div class="master-editor master-add-form">${languageFields(`add-${cat}`,{en:'',de:'',it:''})}<div class="master-entry-actions"><button class="primary" data-action="add-save">${t('add')}</button><button class="secondary" data-action="add-cancel">${t('cancel')}</button></div></div>`:`<button class="secondary master-add-button" data-action="add-open"><span aria-hidden="true">＋</span>${t('addNewEntry')}</button>`}
d.addEventListener('input',e=>{if(e.target.matches('input[data-lang]')){const entry=e.target.closest('.master-entry');if(entry)masterDrafts[entry.dataset.key]=readLanguageFields(entry)}});d.addEventListener('click',e=>{const btn=e.target.closest('button[data-action]');if(!btn)return;const action=btn.dataset.action,entry=btn.closest('.master-entry');if(action==='toggle'){openReasonCats.has(reasonCat)?openReasonCats.delete(reasonCat):openReasonCats.add(reasonCat);redraw()}else if(action==='edit'){const i=Number(btn.dataset.i);masterEditKey=masterKey(cat,i);masterDrafts[masterEditKey]=draftFrom(arr[i]);redraw()}else if(action==='delete'){arr.splice(Number(btn.dataset.i),1);masterEditKey=null;masterDrafts={};save();renderAll()}else if(action==='save'&&entry){const i=Number(btn.dataset.i);arr[i].labels=readLanguageFields(entry);masterEditKey=null;delete masterDrafts[entry.dataset.key];save();renderAll()}else if(action==='cancel'&&entry){delete masterDrafts[entry.dataset.key];masterEditKey=null;redraw()}else if(action==='add-open'){masterAddKey=cat;redraw()}else if(action==='add-cancel'){masterAddKey=null;redraw()}else if(action==='add-save'){const values=readLanguageFields(add);if(Object.values(values).some(Boolean)){arr.push({id:makeId(values.en||values.de||values.it),labels:values});save();masterAddKey=null;renderAll()}}});redraw();return d}
function exportCsv(){const heads=['date','shift','team','timeSlot','project','product','machine','target','produced','scrap','good','deviation','lost','achievement','downtime','lossCategory','lossReason','action','comment'];const rows=filtered().map(e=>{const c=calc(e);return heads.map(h=>h==='good'?c.good:h==='deviation'?c.dev:h==='lost'?c.lost:h==='achievement'?Math.round(c.ach):['shift','team','project','product','machine','lossCategory','lossReason'].includes(h)?label(e[h]??''):e[h]??'')});download(t('csvFilename'),[heads.map(t),...rows].map(r=>r.map(csvEscape).join(';')).join('\n'),'text/csv;charset=utf-8')}
function csvEscape(v){return `"${String(v??'').replaceAll('"','""')}"`}
function download(name,data,type){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([data],{type}));a.download=name;a.click();URL.revokeObjectURL(a.href)}
let pendingCsvRows=null;
const importFields=['date','shift','team','timeSlot','project','product','machine','target','produced','scrap','downtime','lossCategory','lossReason','action','comment'];
function importJson(e){const f=e.target.files[0];if(!f)return;const r=new FileReader();r.onload=()=>{try{const data=JSON.parse(r.result);master=normalizeMaster(data.master||defaultMaster);entries=(data.entries||[]).map(normalizeEntry);save();flash('imported');renderAll()}catch{setValidationMessage(t('importError'),'error')}finally{e.target.value=''}};r.readAsText(f)}
function importCsv(e){const f=e.target.files[0];if(!f)return;const input=e.target,r=new FileReader();r.onload=()=>{try{pendingCsvRows=parseCsvImport(String(r.result||''));$('csvImportDialog').showModal()}catch{pendingCsvRows=null;setValidationMessage(t('csvImportError'),'error');input.value=''}};r.readAsText(f,'UTF-8')}
function closeCsvImportDialog(){const d=$('csvImportDialog');if(d.open)d.close();$('importCsv').value=''}
function applyCsvImport(mode){if(!pendingCsvRows)return closeCsvImportDialog();const existing=mode==='replace'?[]:[...entries],seen=new Set(existing.map(duplicateKey));let imported=0,duplicates=0;pendingCsvRows.valid.forEach(e=>{const key=duplicateKey(e);if(mode==='append'&&seen.has(key)){duplicates++;return}seen.add(key);existing.push({...e,id:crypto.randomUUID()});imported++});entries=existing;master=pendingCsvRows.master;const invalid=pendingCsvRows.invalid;pendingCsvRows=null;save();closeCsvImportDialog();setValidationMessage(t('csvImportSummary').replace('{imported}',imported).replace('{duplicates}',duplicates).replace('{invalid}',invalid),'success');renderAll()}
function parseCsvImport(text){const rows=parseCsv(text.replace(/^\uFEFF/,''));if(rows.length<2)throw new Error('empty');const header=rows[0].map(normalizeHeader),map={};importFields.forEach(f=>{const i=header.findIndex(h=>['en','de','it'].some(l=>h===normalizeHeader(tx[l][f]||tx.en[f]||f))||h===normalizeHeader(f));if(i>=0)map[f]=i});if(['date','shift','team','timeSlot','project','product','machine','target','produced','scrap'].some(f=>map[f]==null))throw new Error('headers');const nextMaster=structuredClone(master);let invalid=0;const valid=[];rows.slice(1).forEach(row=>{if(!row.some(c=>String(c).trim()))return;const e=csvRowToEntry(row,map,nextMaster);if(e)valid.push(e);else invalid++});return {valid,invalid,master:normalizeMaster(nextMaster)}}
function parseCsv(text){const rows=[];let row=[],cell='',q=false;for(let i=0;i<text.length;i++){const ch=text[i],nx=text[i+1];if(q){if(ch==='"'&&nx==='"'){cell+='"';i++}else if(ch==='"')q=false;else cell+=ch}else if(ch==='"')q=true;else if(ch===';'){row.push(cell);cell=''}else if(ch==='\n'){row.push(cell);rows.push(row);row=[];cell=''}else if(ch==='\r'){}else cell+=ch}row.push(cell);rows.push(row);return rows}
function normalizeHeader(v){return String(v||'').trim().toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,'')}
function csvRowToEntry(row,map,nextMaster){const get=f=>String(row[map[f]]??'').trim(),num=f=>{const raw=get(f).replace(/\s/g,'').replace(',','.');return raw===''?NaN:Number(raw)};const target=num('target'),produced=num('produced'),scrap=num('scrap'),downtime=map.downtime==null?0:num('downtime');const e={date:get('date'),shift:mapSystem(get('shift'),systemShifts),team:mapSystem(get('team'),systemTeams),timeSlot:get('timeSlot'),project:ensureImportedMaster(nextMaster,'projects',get('project')),product:ensureImportedMaster(nextMaster,'products',get('product')),machine:ensureImportedMaster(nextMaster,'machines',get('machine')),target,produced,scrap,downtime,lossCategory:mapLossCategory(get('lossCategory')),lossReason:'',action:get('action'),comment:get('comment')};e.lossReason=mapLossReason(e.lossCategory,get('lossReason'),nextMaster);const needsReason=calc(e).lost>0||scrap>0||downtime>0;if(!e.date||!/^\d{4}-\d{2}-\d{2}$/.test(e.date)||!e.shift||!e.team||!e.timeSlot||!e.project||!e.product||!e.machine||[target,produced,scrap,downtime].some(v=>!Number.isFinite(v)||v<0)||scrap>produced||downtime>60||(get('lossCategory')&&!e.lossCategory)||(get('lossReason')&&!e.lossReason)||(needsReason&&(!e.lossCategory||!e.lossReason)))return null;return e}
function mapSystem(value,keys){const v=String(value||'').trim();return keys.find(k=>k===v||systemLabels.en[k]===v||systemLabels.de[k]===v||systemLabels.it[k]===v)||''}
function ensureImportedMaster(m,cat,value){const v=String(value||'').trim();if(!v)return '';const found=m[cat].find(item=>[item.id,item.labels?.en,item.labels?.de,item.labels?.it].includes(v));if(found)return found.id;const item={id:makeId(v),labels:{en:v,de:v,it:v}};let n=2;while(m[cat].some(x=>x.id===item.id))item.id=`${makeId(v)}_${n++}`;m[cat].push(item);return item.id}
function mapLossCategory(value){const v=String(value||'').trim();if(!v)return '';return Object.keys(defaultMaster.reasons).find(k=>k===v||masterLabels.de[k]===v||masterLabels.it[k]===v||masterLabels.en?.[k]===v)||''}
function mapLossReason(cat,value,m){const v=String(value||'').trim();if(!cat||!v)return '';const found=(m.reasons[cat]||[]).find(item=>[item.id,item.labels?.en,item.labels?.de,item.labels?.it,masterLabels.de[item.labels?.en],masterLabels.it[item.labels?.en]].includes(v));return found?.id||''}
function duplicateKey(e){return JSON.stringify(importFields.map(f=>e[f]??''))}
function escapeHtml(value){return String(value).replace(/[&<>'"]/g,ch=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[ch]))}
function renderAll(){translateStatic();renderSelects();renderCalc();renderTable();renderSummary();renderManagementSummary();renderCharts();renderMaster()} init();
